import { SCORING, INTERVALS, SEARCH_CONFIG } from '../strettoConstants';
import { StrettoGrid } from './strettoGrid';

function isDissonant(lo: number, hi: number, lowerIsBass: boolean): boolean {
    const s = (hi - lo) % 12;
    if (INTERVALS.DISSONANT_SIMPLE.has(s)) return true;
    if (s === 5 && lowerIsBass) return true; 
    return false;
}

function isParallelPerfect(lo: number, hi: number): boolean {
    const s = (hi - lo) % 12;
    return s === 0 || s === 7;
}

function getVoiceName(index: number, total: number, names?: Record<number, string>): string {
    if (names && names[index]) return names[index];
    return getVoiceLabel(index, total);
}

function getPitchBitmask(activeVoiceMap: { [voiceIdx: number]: { pitch: number } }): string {
    const keys = Object.keys(activeVoiceMap).sort();
    let mask = "";
    keys.forEach(k => {
        mask += `${k}:${activeVoiceMap[parseInt(k)].pitch}|`;
    });
    return mask;
}

export function validatePair(
    subA: InternalSubjectNote[], 
    subB: InternalSubjectNote[], 
    delay16: number,
    transpositionDiff: number,
    len16: number
): boolean {
    // Quick Rule 5 & 6 Check for a single pair
    // Used during Atom Generation

    // We can simulate a mini-timeline walk or use a simplified intersection check
    // Since this is 2 voices, we just check overlap region

    const offsetB = delay16;

    // Intersection range
    // A: 0 to len16
    // B: offsetB to offsetB + len16
    const startOverlap = offsetB;
    const endOverlap = len16; // A ends here (assuming B starts later, A ends first usually)

    if (startOverlap >= endOverlap) return true; // No overlap = valid

    // Check Parallels & Dissonance
    // We'll iterate the overlap tick by tick (perf optimization: jump by note changes)

    // Merge time points
    const timePoints = new Set<number>();
    subA.forEach(n => {
        if(n.relTick16 >= startOverlap && n.relTick16 < endOverlap) timePoints.add(n.relTick16);
    });
    subB.forEach(n => {
        const absT = offsetB + n.relTick16;
        if(absT >= startOverlap && absT < endOverlap) timePoints.add(absT);
    });
    const sortedT = Array.from(timePoints).sort((a,b)=>a-b);

    let prevP1 = -999;
    let prevP2 = -999;
    let consecutiveDissTicks = 0;

    for (let i = 0; i < sortedT.length; i++) {
        const t = sortedT[i];
        const dur = (i < sortedT.length - 1) ? sortedT[i+1] - t : 1;

        // Find active notes
        const nA = subA.find(n => n.relTick16 <= t && (n.relTick16 + n.dur16) > t);
        const nB = subB.find(n => {
            const absStart = offsetB + n.relTick16;
            return absStart <= t && (absStart + n.dur16) > t;
        });

        if (nA && nB) {
            const p1 = nA.pitch;
            const p2 = nB.pitch + transpositionDiff;

            // Parallel Check (Rule 5)
            if (prevP1 !== -999) {
                if (p1 !== prevP1 && p2 !== prevP2) {
                    // Both moved
                    const int1 = (Math.max(prevP1, prevP2) - Math.min(prevP1, prevP2)) % 12;
                    const int2 = (Math.max(p1, p2) - Math.min(p1, p2)) % 12;
                    if ((int2 === 0 || int2 === 7) && int1 === int2) {
                        return false; // Parallel Error
                    }
                }
            }
            prevP1 = p1;
            prevP2 = p2;

            // Dissonance Check (Rule 6)
            const lo = Math.min(p1, p2);
            const hi = Math.max(p1, p2);
            const isDiss = isDissonant(lo, hi, true); // Bass is always one of them

            if (isDiss) {
                consecutiveDissTicks += dur;
                if (consecutiveDissTicks > SEARCH_CONFIG.MAX_DISSONANCE_TICKS) return false;
            } else {
                consecutiveDissTicks = 0;
            }
        } else {
            prevP1 = -999;
            consecutiveDissTicks = 0;
        }
    }

    return true;
}

export function checkRulesAndStats(
    specs: StrettoChainOption[], 
    baseSubject: InternalSubjectNote[], 
    invertedSubject: InternalSubjectNote[],
    requireConsonantEnd: boolean,
    totalVoices: number,
    voiceNames?: Record<number, string>
): ValidationResult {

    const tl = buildTimeline(specs, baseSubject, invertedSubject);
    const ticks = Object.keys(tl).map(Number).sort((a,b) => a-b);
    const errors: string[] = [];
    const warnings: string[] = [];
    const usedVoices = new Set<number>();
    specs.forEach(s => usedVoices.add(s.voiceIndex));
    const voices = Array.from(usedVoices).sort((a,b) => a-b);

    let polyphonyIntegral = 0;
    let totalDuration = 0;
    let polyphonicDuration = 0;
    let dissonantDuration = 0; 

    // State tracking for Rule 6 (Dissonance Runs)
    let consecutiveDissTicks = 0;
    let consecutiveDissEvents = 0;
    let lastDissPitchMask = "";

    if (ticks.length > 0) {
        const minT = ticks[0];
        const maxT = ticks[ticks.length - 1];
        totalDuration = maxT - minT + 1;

        for (let t = minT; t <= maxT; t++) {
            const activeVoiceMap = tl[t];

            if (!activeVoiceMap || Object.keys(activeVoiceMap).length < 2) {
                consecutiveDissTicks = 0;
                consecutiveDissEvents = 0;
                lastDissPitchMask = "";
                if (activeVoiceMap && Object.keys(activeVoiceMap).length > 0) {
                    polyphonyIntegral += (Object.keys(activeVoiceMap).length - SCORING.POLYPHONY_OFFSET);
                }
                continue; 
            }

            const activeCount = Object.keys(activeVoiceMap).length;
            polyphonyIntegral += (activeCount - SCORING.POLYPHONY_OFFSET);
            polyphonicDuration += 1;

            const pitches: number[] = [];
            const activeIndices = Object.keys(activeVoiceMap).map(Number);
            activeIndices.forEach(v => pitches.push(activeVoiceMap[v].pitch));
            pitches.sort((a,b) => a-b);
            const bassPitch = pitches[0];
            const bassVoiceIdx = parseInt(Object.keys(activeVoiceMap).find(k => activeVoiceMap[parseInt(k)].pitch === bassPitch) || "-1");

            let isMomentDissonant = false;

            for (let i = 0; i < activeIndices.length; i++) {
                for (let j = i + 1; j < activeIndices.length; j++) {
                    const vA = activeIndices[i];
                    const vB = activeIndices[j];
                    const p1 = activeVoiceMap[vA].pitch;
                    const p2 = activeVoiceMap[vB].pitch;
                    const lo = Math.min(p1, p2);
                    const hi = Math.max(p1, p2);
                    const isBassPair = (vA === bassVoiceIdx || vB === bassVoiceIdx);

                    if (isDissonant(lo, hi, isBassPair)) {
                        isMomentDissonant = true;
                        break; 
                    }
                }
                if (isMomentDissonant) break;
            }

            const currentPitchMask = getPitchBitmask(activeVoiceMap);

            if (isMomentDissonant) {
                dissonantDuration += 1;
                consecutiveDissTicks++;

                if (currentPitchMask !== lastDissPitchMask) {
                    consecutiveDissEvents++;
                    lastDissPitchMask = currentPitchMask;
                }

                if (consecutiveDissTicks > SEARCH_CONFIG.MAX_DISSONANCE_TICKS) {
                    errors.push(`Dissonance exceeds 1 Beat at tick ${t}`);
                }

                if (consecutiveDissEvents > SEARCH_CONFIG.MAX_DISSONANCE_EVENTS) {
                    errors.push(`More than 2 consecutive dissonant events at tick ${t}`);
                }

            } else {
                consecutiveDissTicks = 0;
                consecutiveDissEvents = 0;
                lastDissPitchMask = "";
            }
        }
    }

    const { reward, penalty, chords } = analyzeStrettoHarmony(tl, ticks);

    for (let i = 0; i < voices.length; i++) {
        for (let j = i + 1; j < voices.length; j++) {
            const vA = voices[i];
            const vB = voices[j];
            const sounding: { t: number, lo: number, hi: number, lowerIsBass: boolean, p1: number, p2: number }[] = [];

            ticks.forEach(t => {
                const v = tl[t];
                if (v[vA] !== undefined && v[vB] !== undefined) {
                    const minAll = Math.min(...Object.values(v).map(d => d.pitch));
                    const p1 = v[vA].pitch;
                    const p2 = v[vB].pitch;
                    const lo = Math.min(p1, p2);
                    const hi = Math.max(p1, p2);
                    sounding.push({ t, lo, hi, lowerIsBass: lo === minAll, p1, p2 });
                }
            });

            if (sounding.length < 2) continue;

            for (let k = 1; k < sounding.length; k++) {
                const prev = sounding[k-1];
                const curr = sounding[k];
                if (prev.p1 === curr.p1 && prev.p2 === curr.p2) continue;
                const p1Moved = prev.p1 !== curr.p1;
                const p2Moved = prev.p2 !== curr.p2;
                if (!p1Moved || !p2Moved) continue; 

                if (isParallelPerfect(curr.lo, curr.hi)) {
                    if (isParallelPerfect(prev.lo, prev.hi)) {
                        const int1 = (prev.hi - prev.lo) % 12;
                        const int2 = (curr.hi - curr.lo) % 12;
                        if (int1 === int2) {
                            errors.push(`Parallel ${int1 === 7 ? '5th' : '8ve'} (${getVoiceName(vA, totalVoices, voiceNames)}, ${getVoiceName(vB, totalVoices, voiceNames)})`);
                        }
                    }
                }
            }
        }
    }

    if (requireConsonantEnd) {
        for (const spec of specs) {
            const start16 = Math.round(spec.startBeat * 4);
            const end16 = start16 + spec.length; 
            const checkTick = end16 - 1;
            const activeVoices = tl[checkTick];
            if (!activeVoices || Object.keys(activeVoices).length < 2) continue;

            const myData = activeVoices[spec.voiceIndex];
            if (!myData) continue;
            const myPitch = myData.pitch;
            const activePitches = Object.values(activeVoices).map(v => v.pitch);
            const bassPitch = Math.min(...activePitches);

            let hasConsonance = false;
            for (const otherVStr in activeVoices) {
                const otherV = parseInt(otherVStr);
                if (otherV === spec.voiceIndex) continue;
                const otherPitch = activeVoices[otherV].pitch;
                const interval = Math.abs(myPitch - otherPitch) % 12;
                if (INTERVALS.CONSONANT.has(interval)) { hasConsonance = true; break; }
                if (interval === 5) {
                    const pairLower = Math.min(myPitch, otherPitch);
                    if (pairLower > bassPitch) { hasConsonance = true; break; }
                }
            }
            if (!hasConsonance) errors.push(`Non-Consonant Ending (${getVoiceName(spec.voiceIndex, totalVoices, voiceNames)})`);
        }
    }

    return { 
        isValid: errors.length === 0, 
        errors, warnings, polyphonyIntegral, totalDuration, polyphonicDuration,
        dissonantDuration, harmonicReward: reward, harmonicPenalty: penalty,
        detectedChords: chords
    };
}

import { RawNote, StrettoChainResult, StrettoSearchOptions, StrettoChainOption, ScoreLog, StrettoSearchReport } from '../../types';
import { SCORING, SEARCH_CONFIG, INTERVALS } from './strettoConstants';
import { normalizeSubject, getEffectiveSubjectLength16, invertPitch } from './stretto/strettoTimeline';
import { checkRulesAndStats, validatePair } from './stretto/strettoRules';
import { InternalSubjectNote, StrettoBlock, StrettoPair } from './stretto/strettoTypes';

// --- Block Assembly Logic ---

// PHASE 1: Generate Atoms (Valid Pairs)
function generateAtoms(
    baseSubject: InternalSubjectNote[], 
    invertedSubject: InternalSubjectNote[], 
    options: StrettoSearchOptions,
    validTranspositions: number[],
    effectiveLen16: number,
    subjectDurationBeats: number
): StrettoPair[] {
    const atoms: StrettoPair[] = [];

    // Delays: 0.5 beat to 2/3 length
    const maxDelayBeats = subjectDurationBeats * (2/3);
    const delays: number[] = [];
    for(let d = 0.5; d <= maxDelayBeats; d += 0.5) delays.push(d);

    // Iterating V(i) vs V(i+1)
    // Rule 4a: s_i >= s_i+1 (Transposition of upper >= lower)
    // We store 'transpositionDiff' = T_bottom - T_top. 
    // So Rule 4a implies T_bottom <= T_top, meaning transpositionDiff <= 0.

    for (const d of delays) {
        const delay16 = Math.round(d * 4);

        for (const tDiff of validTranspositions) {
            // Rule 4a Check: Lower voice must be lower or equal transposition
            if (tDiff > 0) continue; 

            // Check Normal Bottom
            if (validatePair(baseSubject, baseSubject, delay16, tDiff, effectiveLen16)) {
                atoms.push({
                    voiceTop: 0, voiceBottom: 1, transpositionDiff: tDiff, delay16, typeBottom: 'N', isValid: true,
                    id: `N-${tDiff}-${d}`
                });
            }

            // Check Inverted Bottom (if enabled)
            if (options.inversionMode !== 'None' && invertedSubject.length > 0) {
                // Heuristic: Only allow perfect intervals for inversion if strict
                if (options.disallowComplexExceptions) {
                    const ic = Math.abs(tDiff % 12);
                    if (![0,5,7].includes(ic)) continue;
                }

                if (validatePair(baseSubject, invertedSubject, delay16, tDiff, effectiveLen16)) {
                    atoms.push({
                        voiceTop: 0, voiceBottom: 1, transpositionDiff: tDiff, delay16, typeBottom: 'I', isValid: true,
                        id: `I-${tDiff}-${d}`
                    });
                }
            }
        }
    }
    return atoms;
}

// PHASE 2 & 3: Recursive Assembly
async function assembleBlocks(
    currentChain: StrettoBlock[],
    atoms: StrettoPair[],
    targetLength: number,
    options: StrettoSearchOptions,
    baseSubject: InternalSubjectNote[],
    invertedSubject: InternalSubjectNote[],
    results: StrettoChainResult[],
    startTime: number
) {
    // Timeout check
    if (Date.now() - startTime > SEARCH_CONFIG.TIME_LIMIT_MS) return;
    if (results.length >= SEARCH_CONFIG.MAX_VALID_RESULTS) return;

    // Base Case: Chain Complete
    if (currentChain.length === targetLength - 1) { // N entries = N-1 links
        // Convert Block structure to Result format
        const entries: StrettoChainOption[] = [];
        let currentAbsBeat = 0;
        let currentAbsTrans = 0;

        entries.push({
            startBeat: 0, transposition: 0, type: 'N', 
            length: currentChain[0].duration16, voiceIndex: 0
        });

        // Reconstruct absolute values from relative links
        currentChain.forEach((link, idx) => {
            // link is the connection between i and i+1
            // In our StrettoPair, delay16 is how much Later the bottom voice is.
            // But wait, atoms were defined as Pair(Top, Bottom).
            // Here 'link' represents the Pair definition used.
            // Actually, we need to store WHICH atom was used.
            // Let's redefine `currentChain` to store StrettoPairs directly.
        });
        return;
    }
}

// Optimized Assembly Function
export async function searchStrettoChains(
    rawSubject: RawNote[],
    options: StrettoSearchOptions,
    ppq: number
): Promise<StrettoSearchReport> {

    const START_TIME = Date.now();
    let nodesVisited = 0;

    const baseSubject = normalizeSubject(rawSubject, ppq);
    if (baseSubject.length === 0) return { results: [], stats: { nodesVisited: 0, timeMs: 0, stopReason: 'Exhausted', maxDepthReached: 0 } };

    const effectiveLen16 = getEffectiveSubjectLength16(baseSubject);
    const subjectDurationBeats = effectiveLen16 / 4;

    // Prep Inversion
    const invertedSubject: InternalSubjectNote[] = [];
    if (options.inversionMode !== 'None') {
        const subjectStartMidi = baseSubject[0].pitch;
        const invertedRaw = baseSubject.map(n => {
            const inv = invertPitch(n.pitch, options.pivotMidi, options.useChromaticInversion);
            return { ...n, pitch: inv !== null ? inv : n.pitch };
        });
        if (invertedRaw.length > 0) {
            const diff = subjectStartMidi - invertedRaw[0].pitch;
            invertedRaw.forEach(n => n.pitch += diff);
        }
        invertedSubject.push(...invertedRaw);
    }

    // 1. Generate Atoms
    const validTranspositions = Array.from(INTERVALS.TRAD_TRANSPOSITIONS);
    if (options.thirdSixthMode !== 'None') {
        INTERVALS.THIRD_SIXTH_TRANSPOSITIONS.forEach(t => {
            if (!validTranspositions.includes(t)) validTranspositions.push(t);
        });
    }

    const atoms = generateAtoms(baseSubject, invertedSubject, options, validTranspositions, effectiveLen16, subjectDurationBeats);

    // 2. Build Chains (DFS with Lookback)
    const validResults: StrettoChainResult[] = [];

    // State for DFS:
    // Chain of entries: [ {absStart, absTrans, type} ]

    const initialEntry = { startBeat: 0, transposition: 0, type: 'N' as const, length: effectiveLen16, voiceIndex: options.subjectVoiceIndex };

    async function dive(chain: StrettoChainOption[]) {
        nodesVisited++;
        if (Date.now() - START_TIME > SEARCH_CONFIG.TIME_LIMIT_MS || validResults.length >= SEARCH_CONFIG.MAX_VALID_RESULTS) return;

        if (chain.length === options.targetChainLength) {
            // Final Validation (Full Ensemble Check)
            const validation = checkRulesAndStats(chain, baseSubject, invertedSubject, options.requireConsonantEnd, options.ensembleTotal, options.voiceNames);
            if (validation.isValid) {
                // Calculate Score
                let score = validation.polyphonyIntegral;
                // Add Bonuses
                if (validation.harmonicReward > 0) score += validation.harmonicReward;

                // Penalties
                const ratio = validation.polyphonicDuration > 0 ? validation.dissonantDuration/validation.polyphonicDuration : 0;
                if (ratio > SCORING.DISS_PENALTY_START) score -= (ratio - SCORING.DISS_PENALTY_START) * SCORING.DISS_PENALTY_SLOPE;

                validResults.push({
                    id: Math.random().toString(36),
                    entries: [...chain],
                    warnings: [],
                    score: Math.max(0, score),
                    detectedChords: validation.detectedChords,
                    dissonanceRatio: ratio,
                    scoreLog: { base: 0, total: score, bonuses: [], penalties: [] } // Simplified log
                });
            }
            return;
        }

        const prevEntry = chain[chain.length - 1];
        const prevPrevEntry = chain.length >= 2 ? chain[chain.length - 2] : null;

        // Calculate allowed delay range based on elasticity history
        // Rule 2: Max Expansion 1.0 beat
        // Rule 1C: Late stage tightening

        const prevDelay = prevPrevEntry ? (prevEntry.startBeat - prevPrevEntry.startBeat) : 0;

        for (const atom of atoms) {
            // Atom represents relative move from Prev -> Curr
            const delayBeats = atom.delay16 / 4;
            const transDiff = atom.transpositionDiff; // Relative change

            // Check Rule 1 (Contraction/Expansion limits)
            if (chain.length >= 2) {
                // Elasticity: New delay cannot be > prevDelay + 1.0
                if (delayBeats > prevDelay + 1.0) continue;

                // Reaction: If prev was expansion, this must contract
                if (chain.length >= 3) {
                    const prevPrevDelay = chain[chain.length - 2].startBeat - chain[chain.length - 3].startBeat;
                    if (prevDelay > prevPrevDelay) {
                        // Previous step expanded
                        if (delayBeats >= prevDelay) continue; // Must contract
                    }
                }
            }

            // Rule 1C: Late Stage Tightening
            if (chain.length >= 3) {
                // 4th entry onwards (index 3+)
                if (delayBeats >= (subjectDurationBeats * 0.5)) continue;
            }

            // Construct Candidate Entry
            const newStart = prevEntry.startBeat + delayBeats;
            const newTrans = prevEntry.transposition + transDiff; // Apply relative change
            const newVoiceIdx = (prevEntry.voiceIndex + 1) % options.ensembleTotal; // Simple cyclic assignment for now or based on chain logic

            // NOTE: The user wants block assembly logic, essentially building down V1->V2->V3.
            // If subject is V_i, next is V_i+1.
            // Let's assume standard descending assembly: V0 -> V1 -> V2
            // But we need to map to the `subjectVoiceIndex` offset.
            // Actually, `atoms` define Top->Bottom relationship.
            // So if we chain atoms, we are building Voice i -> Voice i+1.

            // Check Global Constraints (V1-V3, V1-V4)
            // We need absolute transpositions relative to the *Topmost* voice (Voice 0 in the chain context)
            const rootTrans = chain[0].transposition;

            // Check V1-V3 Stratification
            if (chain.length === 2) { // We are adding the 3rd voice (Index 2)
                const v1_Trans = chain[0].transposition;
                const v3_Trans = newTrans;
                // Rule 4b: V1 - V3 >= 7 (P5)
                // Since we are going down, V1 is higher. V1 - V3 should be positive.
                if ((v1_Trans - v3_Trans) < SEARCH_CONFIG.MIN_SEPARATION_V1_V3) continue;
            }

            // Check V1-V4 Stratification
            if (chain.length === 3) { // Adding 4th voice
                const v1_Trans = chain[0].transposition;
                const v4_Trans = newTrans;
                // Rule 4c: V1 - V4 >= 19
                if ((v1_Trans - v4_Trans) < SEARCH_CONFIG.MIN_SEPARATION_V1_V4) continue;
            }

            // Check Range Limit (3 Octaves)
            if ((rootTrans - newTrans) > SEARCH_CONFIG.MAX_TOTAL_RANGE) continue;

            // Partial Structure Validation (Expensive)
            // We verify the new block [ ...chain, newEntry ]
            const newEntryObj: StrettoChainOption = {
                startBeat: newStart,
                transposition: newTrans,
                type: atom.typeBottom,
                length: effectiveLen16, // Simplify length for now
                voiceIndex: chain.length // Sequential index 0,1,2... mapped later
            };

            const tempChain = [...chain, newEntryObj];

            // Validate Partial Harmony (Rule 6 on composite)
            // We use the full checkRules function but rely on it handling partials correctly
            const res = checkRulesAndStats(tempChain, baseSubject, invertedSubject, false, chain.length + 1, options.voiceNames);
            if (!res.isValid) continue;

            await dive(tempChain);
        }
    }

    // Start assembly assuming Subject is the Top Voice (Voice 0 relative) 
    // We will remap to the requested `subjectVoiceIndex` at the end or handle it via sorting
    // Actually, Stretto usually implies Subject is highest or lowest. 
    // If Subject is Voice 2 (Tenor), then V1 (Alto) and V0 (Soprano) must be calculated 'upwards'.
    // The Atom generator only generated Top->Bottom atoms.
    // For this implementation, we will assume constructing a chain *downwards* from the Subject.
    // i.e. Subject is the highest voice in the chain logic, then we shift indices.

    // Fix: If Subject is VoiceIndex 2, we actually want to find voices 3, 4... below it?
    // OR are we finding the whole ensemble?
    // Block Assembly typically builds the whole texture.
    // Let's assume we build V0->V1->V2->V3. 
    // If the user wants the Subject to be V2, we just treat the resulting chain's V0 as V2? 
    // No, that changes intervals. 

    // Simplified assumption for v5.0: Subject is V0 (Top).
    // We construct V0, V1, V2...

    await dive([initialEntry]);

    validResults.sort((a,b) => b.score - a.score);

    return {
        results: validResults.slice(0, 50),
        stats: {
            nodesVisited, 
            timeMs: Date.now() - START_TIME,
            stopReason: validResults.length > 0 ? 'Success' : 'Exhausted',
            maxDepthReached: options.targetChainLength
        }
    };
}

