import { getVoiceLabel } from '../midiVoices';
import { SCORING, INTERVALS, SEARCH_CONFIG } from '../strettoConstants';

function isDissonant(lo: number, hi: number, lowerIsBass: boolean): boolean {
    const s = (hi - lo) % 12;
    if (INTERVALS.DISSONANT_SIMPLE.has(s)) return true;
    if (s === 5 && lowerIsBass) return true; 
    return false;
}

function isParallelPerfect(lo: number, hi: number): boolean {
    const s = (hi - lo) % 12;
    return s === 0 || s === 7;
}

function getVoiceName(index: number, total: number, names?: Record<number, string>): string {
    if (names && names[index]) return names[index];
    return getVoiceLabel(index, total);
}

function getPitchBitmask(activeVoiceMap: { [voiceIdx: number]: { pitch: number } }): string {
    const keys = Object.keys(activeVoiceMap).sort();
    let mask = "";
    keys.forEach(k => {
        mask += `${k}:${activeVoiceMap[parseInt(k)].pitch}|`;
    });
    return mask;
}

// Optimized 2-Voice Check
export function validatePair(
    subA: InternalSubjectNote[], 
    subB: InternalSubjectNote[], 
    delay16: number,
    transpositionDiff: number,
    len16: number
): boolean {
    // Basic Intersection Check
    const startOverlap = delay16;
    const endOverlap = len16; // A ends at len16

    if (startOverlap >= endOverlap) return true; // No overlap = trivially valid (though musically boring)

    // Check Parallels & Dissonance
    // Iterate notes in A that fall in overlap

    // Quick Perf: Pre-calculate active B intervals? 
    // Or just iterate ticks. For 2 voices, ticks is acceptable.

    let prevP1 = -999;
    let prevP2 = -999;
    let consecutiveDissTicks = 0;

    // Use a set of interesting time points (note onsets/offsets)
    const timePoints = new Set<number>();
    subA.forEach(n => {
        if(n.relTick16 >= startOverlap && n.relTick16 < endOverlap) timePoints.add(n.relTick16);
    });
    subB.forEach(n => {
        const absStart = delay16 + n.relTick16;
        if(absStart >= startOverlap && absStart < endOverlap) timePoints.add(absStart);
    });

    const sortedT = Array.from(timePoints).sort((a,b)=>a-b);

    for (let i = 0; i < sortedT.length; i++) {
        const t = sortedT[i];
        const dur = (i < sortedT.length - 1) ? sortedT[i+1] - t : 1;

        // Resolve Notes
        // A starts at 0. B starts at delay16.
        const nA = subA.find(n => n.relTick16 <= t && (n.relTick16 + n.dur16) > t);
        const nB = subB.find(n => {
            const absStart = delay16 + n.relTick16;
            return absStart <= t && (absStart + n.dur16) > t;
        });

        if (nA && nB) {
            const p1 = nA.pitch;
            const p2 = nB.pitch + transpositionDiff;

            // Parallel Check (Rule 5 - Local)
            if (prevP1 !== -999) {
                if (p1 !== prevP1 && p2 !== prevP2) {
                    const int1 = (Math.max(prevP1, prevP2) - Math.min(prevP1, prevP2)) % 12;
                    const int2 = (Math.max(p1, p2) - Math.min(p1, p2)) % 12;

                    if ((int2 === 0 || int2 === 7) && int1 === int2) {
                        return false; // Parallel Error
                    }
                }
            }
            prevP1 = p1;
            prevP2 = p2;

            // Dissonance Check (Rule 6 - Local)
            const lo = Math.min(p1, p2);
            const hi = Math.max(p1, p2);
            // In 2-voice texture, lowest is always bass
            const isDiss = isDissonant(lo, hi, true);

            if (isDiss) {
                consecutiveDissTicks += dur;
                if (consecutiveDissTicks > SEARCH_CONFIG.MAX_DISSONANCE_TICKS) return false;
            } else {
                consecutiveDissTicks = 0;
            }
        } else {
            // One voice dropped out
            prevP1 = -999;
            consecutiveDissTicks = 0;
        }
    }

    return true;
}

// Optimized 3-Voice Check (Builds on valid pairs)
export function validateTriple(
    atom1: StrettoPair,
    atom2: StrettoPair,
    baseSubject: InternalSubjectNote[],
    invertedSubject: InternalSubjectNote[],
    len16: number
): boolean {
    // Construct the 3rd voice relative to Voice 0 (Subject)
    // V0: 0, 0
    // V1: atom1.delay, atom1.trans
    // V2: atom1.delay + atom2.delay, atom1.trans + atom2.trans

    const d1 = atom1.delay16;
    const t1 = atom1.transpositionDiff;
    const d2 = d1 + atom2.delay16;
    const t2 = t1 + atom2.transpositionDiff;

    // We only need to check V0 vs V2 interactions, and the overall dissonance
    // V0-V1 is valid (atom1). V1-V2 is valid (atom2).
    // Primary new risk: Parallel 5ths between V0 and V2 (Outer voices of the triple).

    // Optimization: Intersect V0 and V2 only?
    // Rule 6 needs all 3 voices.

    // For performance, let's do a simplified check first: V0 vs V2 Parallels
    const sub1 = baseSubject; // V0 is always Normal Subject in this context? 
                              // Actually, if V0 is Inverted, everything shifts.
                              // Let's assume input implies V0 is Normal base for now.

    const sub2 = atom2.typeBottom === 'N' ? baseSubject : invertedSubject;
    // Wait, atom2.typeBottom is relative to atom1.
    // If atom1 is 'N', V1 is Normal. So atom2 'N' means V2 is Normal.
    // If atom1 is 'I', V1 is Inverted. atom2 is relative to V1. 
    // This gets complex. Let's rely on the full checkRulesAndStats for the 3-voice block
    // but pass it a constructed mini-chain.

    const chain: StrettoChainOption[] = [
        { startBeat: 0, transposition: 0, type: 'N', length: len16, voiceIndex: 0 },
        { startBeat: d1/4, transposition: t1, type: atom1.typeBottom, length: len16, voiceIndex: 1 },
        { startBeat: d2/4, transposition: t2, type: atom2.typeBottom, length: len16, voiceIndex: 2 }
    ];

    // We use the full checker but expect it to be fast enough for N=3
    const res = checkRulesAndStats(chain, baseSubject, invertedSubject, false, 3);
    return res.isValid;
}

export function checkRulesAndStats(
    specs: StrettoChainOption[], 
    baseSubject: InternalSubjectNote[], 
    invertedSubject: InternalSubjectNote[],
    requireConsonantEnd: boolean,
    totalVoices: number,
    voiceNames?: Record<number, string>
): ValidationResult {

    const tl = buildTimeline(specs, baseSubject, invertedSubject);
    const ticks = Object.keys(tl).map(Number).sort((a,b) => a-b);
    const errors: string[] = [];
    const warnings: string[] = [];
    const usedVoices = new Set<number>();
    specs.forEach(s => usedVoices.add(s.voiceIndex));
    const voices = Array.from(usedVoices).sort((a,b) => a-b);

    let polyphonyIntegral = 0;
    let totalDuration = 0;
    let polyphonicDuration = 0;
    let dissonantDuration = 0; 

    let consecutiveDissTicks = 0;
    let consecutiveDissEvents = 0;
    let lastDissPitchMask = "";

    if (ticks.length > 0) {
        const minT = ticks[0];
        const maxT = ticks[ticks.length - 1];
        totalDuration = maxT - minT + 1;

        for (let t = minT; t <= maxT; t++) {
            const activeVoiceMap = tl[t];

            if (!activeVoiceMap || Object.keys(activeVoiceMap).length < 2) {
                consecutiveDissTicks = 0;
                consecutiveDissEvents = 0;
                lastDissPitchMask = "";
                if (activeVoiceMap && Object.keys(activeVoiceMap).length > 0) {
                    polyphonyIntegral += (Object.keys(activeVoiceMap).length - SCORING.POLYPHONY_OFFSET);
                }
                continue; 
            }

            const activeCount = Object.keys(activeVoiceMap).length;
            polyphonyIntegral += (activeCount - SCORING.POLYPHONY_OFFSET);
            polyphonicDuration += 1;

            const pitches: number[] = [];
            const activeIndices = Object.keys(activeVoiceMap).map(Number);
            activeIndices.forEach(v => pitches.push(activeVoiceMap[v].pitch));
            pitches.sort((a,b) => a-b);
            const bassPitch = pitches[0];
            const bassVoiceIdx = parseInt(Object.keys(activeVoiceMap).find(k => activeVoiceMap[parseInt(k)].pitch === bassPitch) || "-1");

            let isMomentDissonant = false;

            for (let i = 0; i < activeIndices.length; i++) {
                for (let j = i + 1; j < activeIndices.length; j++) {
                    const vA = activeIndices[i];
                    const vB = activeIndices[j];
                    const p1 = activeVoiceMap[vA].pitch;
                    const p2 = activeVoiceMap[vB].pitch;
                    const lo = Math.min(p1, p2);
                    const hi = Math.max(p1, p2);
                    const isBassPair = (vA === bassVoiceIdx || vB === bassVoiceIdx);

                    if (isDissonant(lo, hi, isBassPair)) {
                        isMomentDissonant = true;
                        break; 
                    }
                }
                if (isMomentDissonant) break;
            }

            const currentPitchMask = getPitchBitmask(activeVoiceMap);

            if (isMomentDissonant) {
                dissonantDuration += 1;
                consecutiveDissTicks++;

                if (currentPitchMask !== lastDissPitchMask) {
                    consecutiveDissEvents++;
                    lastDissPitchMask = currentPitchMask;
                }

                if (consecutiveDissTicks > SEARCH_CONFIG.MAX_DISSONANCE_TICKS) {
                    errors.push(`Dissonance exceeds 1 Beat at tick ${t}`);
                }

                if (consecutiveDissEvents > SEARCH_CONFIG.MAX_DISSONANCE_EVENTS) {
                    errors.push(`More than 2 consecutive dissonant events at tick ${t}`);
                }

            } else {
                consecutiveDissTicks = 0;
                consecutiveDissEvents = 0;
                lastDissPitchMask = "";
            }
        }
    }

    const { reward, penalty, chords } = analyzeStrettoHarmony(tl, ticks);

    for (let i = 0; i < voices.length; i++) {
        for (let j = i + 1; j < voices.length; j++) {
            const vA = voices[i];
            const vB = voices[j];
            const sounding: { t: number, lo: number, hi: number, lowerIsBass: boolean, p1: number, p2: number }[] = [];

            ticks.forEach(t => {
                const v = tl[t];
                if (v[vA] !== undefined && v[vB] !== undefined) {
                    const minAll = Math.min(...Object.values(v).map(d => d.pitch));
                    const p1 = v[vA].pitch;
                    const p2 = v[vB].pitch;
                    const lo = Math.min(p1, p2);
                    const hi = Math.max(p1, p2);
                    sounding.push({ t, lo, hi, lowerIsBass: lo === minAll, p1, p2 });
                }
            });

            if (sounding.length < 2) continue;

            for (let k = 1; k < sounding.length; k++) {
                const prev = sounding[k-1];
                const curr = sounding[k];
                if (prev.p1 === curr.p1 && prev.p2 === curr.p2) continue;
                const p1Moved = prev.p1 !== curr.p1;
                const p2Moved = prev.p2 !== curr.p2;
                if (!p1Moved || !p2Moved) continue; 

                if (isParallelPerfect(curr.lo, curr.hi)) {
                    if (isParallelPerfect(prev.lo, prev.hi)) {
                        const int1 = (prev.hi - prev.lo) % 12;
                        const int2 = (curr.hi - curr.lo) % 12;
                        if (int1 === int2) {
                            errors.push(`Parallel ${int1 === 7 ? '5th' : '8ve'} (${getVoiceName(vA, totalVoices, voiceNames)}, ${getVoiceName(vB, totalVoices, voiceNames)})`);
                        }
                    }
                }
            }
        }
    }

    if (requireConsonantEnd) {
        for (const spec of specs) {
            const start16 = Math.round(spec.startBeat * 4);
            const end16 = start16 + spec.length; 
            const checkTick = end16 - 1;
            const activeVoices = tl[checkTick];
            if (!activeVoices || Object.keys(activeVoices).length < 2) continue;

            const myData = activeVoices[spec.voiceIndex];
            if (!myData) continue;
            const myPitch = myData.pitch;
            const activePitches = Object.values(activeVoices).map(v => v.pitch);
            const bassPitch = Math.min(...activePitches);

            let hasConsonance = false;
            for (const otherVStr in activeVoices) {
                const otherV = parseInt(otherVStr);
                if (otherV === spec.voiceIndex) continue;
                const otherPitch = activeVoices[otherV].pitch;
                const interval = Math.abs(myPitch - otherPitch) % 12;
                if (INTERVALS.CONSONANT.has(interval)) { hasConsonance = true; break; }
                if (interval === 5) {
                    const pairLower = Math.min(myPitch, otherPitch);
                    if (pairLower > bassPitch) { hasConsonance = true; break; }
                }
            }
            if (!hasConsonance) errors.push(`Non-Consonant Ending (${getVoiceName(spec.voiceIndex, totalVoices, voiceNames)})`);
        }
    }

    return { 
        isValid: errors.length === 0, 
        errors, warnings, polyphonyIntegral, totalDuration, polyphonicDuration,
        dissonantDuration, harmonicReward: reward, harmonicPenalty: penalty,
        detectedChords: chords
    };
}

