    type: 'N' | 'I';           // Inversion status
    isValid: boolean;
    id: string;
}

import { RawNote, StrettoChainResult, StrettoSearchOptions, StrettoChainOption, ScoreLog, StrettoSearchReport } from '../../types';
import { SCORING, INTERVALS, SEARCH_CONFIG } from './strettoConstants';
import { StrettoGrid } from './stretto/strettoGrid';
import { normalizeSubject, getEffectiveSubjectLength16, invertPitch } from './stretto/strettoTimeline';
import { checkRulesAndStats, validatePair } from './stretto/strettoRules';
import { InternalSubjectNote, ValidationResult, StrettoAtom } from './stretto/strettoTypes';

// --- Phase 1: Atom Generation ---

function generateAtoms(
    baseSubject: InternalSubjectNote[],
    invertedSubject: InternalSubjectNote[],
    options: StrettoSearchOptions,
    validTranspositions: number[],
    effectiveLen16: number,
    subjectDurationBeats: number
): StrettoAtom[] {
    const atoms: StrettoAtom[] = [];

    // Search Step Resolution: 0.5 Beats (Eighth Note)
    const delays: number[] = [];

    // Rule 1A: Max Delay <= 2/3 Length
    const maxDelay = Math.floor(subjectDurationBeats * SEARCH_CONFIG.ATOM_MAX_DELAY_RATIO * 2) / 2; // Floor to nearest 0.5

    for(let d = 0.5; d <= maxDelay; d += 0.5) delays.push(d);

    const types: {type: 'N'|'I', source: InternalSubjectNote[]}[] = [];
    types.push({ type: 'N', source: baseSubject });
    if (options.inversionMode !== 'None' && invertedSubject.length > 0) {
        types.push({ type: 'I', source: invertedSubject });
    }

    for (const d of delays) {
        for (const t of validTranspositions) {
            for (const typeObj of types) {
                // Pre-check complex exceptions if flag is set
                if (options.disallowComplexExceptions && typeObj.type === 'I') {
                    const intervalClass = Math.abs(t % 12);
                    const isPerfect = [0, 5, 7].includes(intervalClass);
                    if (!isPerfect) continue; 
                }

                // Create a temporary pair [Voice0, Voice1] to validate Rule 5 (Parallels) and Rule 6 (Local Diss)
                // Note: Atom is relative. Voice0 is implicitly at (0,0). Voice1 is at (d, t).
                // We use checkRulesAndStats for robust checking, but optimize for N=2

                // Construct normalized Pair
                const pairChain: StrettoChainOption[] = [
                    { startBeat: 0, transposition: 0, type: 'N', length: effectiveLen16, voiceIndex: 0 },
                    { startBeat: d, transposition: t, type: typeObj.type, length: effectiveLen16, voiceIndex: 1 }
                ];

                // For Atom generation, we ignore Consonant End (it's a chain property)
                // We assume Ensemble=2 for the check
                // This internally calls Rule 5 and Rule 6 checkers
                const validation = checkRulesAndStats(pairChain, baseSubject, invertedSubject, false, 2, options.voiceNames);

                if (validation.isValid) {
                    atoms.push({
                        transpositionDiff: t,
                        delayBeats: d,
                        type: typeObj.type,
                        isValid: true,
                        id: `${d}@${t}${typeObj.type}`
                    });
                }
            }
        }
    }

    return atoms;
}

// --- Phase 2: Chain Assembly (The Zipper) ---

export async function searchStrettoChains(
    rawSubject: RawNote[],
    options: StrettoSearchOptions,
    ppq: number
): Promise<StrettoSearchReport> {

    const START_TIME = Date.now();
    let nodesVisited = 0;
    let stopReason: 'Success' | 'Timeout' | 'NodeLimit' | 'Exhausted' = 'Exhausted';
    let maxDepthReached = 0;

    const baseSubject = normalizeSubject(rawSubject, ppq);
    if (baseSubject.length === 0) {
        return { results: [], stats: { nodesVisited: 0, timeMs: 0, stopReason: 'Exhausted', maxDepthReached: 0 } };
    }

    const effectiveLen16 = getEffectiveSubjectLength16(baseSubject);
    const subjectDurationBeats = effectiveLen16 / 4;

    // Prepare Inversion
    const invertedSubject: InternalSubjectNote[] = [];
    if (options.inversionMode !== 'None') {
        const subjectStartMidi = baseSubject.length > 0 ? baseSubject[0].pitch : options.pivotMidi;
        const invertedRaw = baseSubject.map(n => {
            const inv = invertPitch(n.pitch, options.pivotMidi, options.useChromaticInversion);
            return { ...n, pitch: inv !== null ? inv : n.pitch };
        });
        if (invertedRaw.length > 0) {
            const currentStart = invertedRaw[0].pitch;
            const diff = subjectStartMidi - currentStart;
            invertedRaw.forEach(n => n.pitch += diff);
        }
        invertedSubject.push(...invertedRaw);
    }

    // Build Transposition List
    const validTranspositions = Array.from(INTERVALS.TRAD_TRANSPOSITIONS);
    if (options.thirdSixthMode !== 'None') {
        INTERVALS.THIRD_SIXTH_TRANSPOSITIONS.forEach(t => {
            if (!validTranspositions.includes(t)) validTranspositions.push(t);
        });
    }

    // GENERATE ATOMS
    const atoms = generateAtoms(baseSubject, invertedSubject, options, validTranspositions, effectiveLen16, subjectDurationBeats);

    // Result Containers
    const validResults: StrettoChainResult[] = [];
    const partialResults: StrettoChainResult[] = []; // Store incomplete but valid chains if we timeout

    // --- RECURSIVE SOLVER ---

    // State for DFS
    interface SearchState {
        chain: StrettoChainOption[];
        voiceEndTimes16: number[]; // Track when each physical voice becomes free
        usedTranspositions: number[]; // For stratification check
        historyDelays: number[]; // For Rule 2 (Elasticity)
        usageStats: { inv: number, third: number, trunc: number };
    }

    const initialVoiceState = new Array(options.ensembleTotal).fill(0);
    // Subject uses Subject Voice
    initialVoiceState[options.subjectVoiceIndex] = effectiveLen16; 

    const rootState: SearchState = {
        chain: [{
            startBeat: 0, transposition: 0, type: 'N',
            length: effectiveLen16, voiceIndex: options.subjectVoiceIndex
        }],
        voiceEndTimes16: initialVoiceState,
        usedTranspositions: [0],
        historyDelays: [],
        usageStats: { inv: 0, third: 0, trunc: 0 }
    };

    const targetLength = options.targetChainLength;

    // Heuristic Sort for Atoms (Try 'tight' and 'consonant' first)
    atoms.sort((a,b) => {
        // Prefer delays closer to 1.0 (not too short, not too long)
        const scoreA = Math.abs(a.delayBeats - 2.0) + (Math.abs(a.transpositionDiff % 12) === 7 ? 0 : 5);
        const scoreB = Math.abs(b.delayBeats - 2.0) + (Math.abs(b.transpositionDiff % 12) === 7 ? 0 : 5);
        return scoreA - scoreB;
    });

    async function solve(state: SearchState) {
        nodesVisited++;
        const currentDepth = state.chain.length;
        if (currentDepth > maxDepthReached) maxDepthReached = currentDepth;

        // --- STOP CONDITIONS ---
        if (validResults.length >= SEARCH_CONFIG.MAX_VALID_RESULTS) { stopReason = 'Success'; return; }
        if (nodesVisited > SEARCH_CONFIG.MAX_VISITED_NODES) { stopReason = 'NodeLimit'; return; }
        if (Date.now() - START_TIME > SEARCH_CONFIG.TIME_LIMIT_MS) { stopReason = 'Timeout'; return; }

        // --- GOAL REACHED ---
        if (currentDepth === targetLength) {
            // Final full validation (just in case complex interactions were missed)
            const validation = checkRulesAndStats(state.chain, baseSubject, invertedSubject, options.requireConsonantEnd, options.ensembleTotal, options.voiceNames);
            if (validation.isValid) {
                processResult(state.chain, validation, validResults);
            }
            return;
        }

        const prevEntry = state.chain[currentDepth - 1];

        // Iterate Atoms to find next link
        for (const atom of atoms) {
            if (stopReason !== 'Exhausted') break;

            // --- CONSTRAINT: Rule 1A Modified (Entry 2 Minimum) ---
            if (currentDepth === 1) {
                // Adding Entry 2. Must be >= 0.4 * L
                if (atom.delayBeats < (subjectDurationBeats * SEARCH_CONFIG.ENTRY2_MIN_DELAY_RATIO)) continue;
            }

            // --- CONSTRAINT: Rule 2A (Elasticity Expansion Limit) ---
            // Δd{ei,ei-1} <= Δd{ei-1,ei-2} + 1.0
            if (currentDepth >= 2) {
                const prevDelay = state.historyDelays[state.historyDelays.length - 1];
                if (atom.delayBeats > prevDelay + SEARCH_CONFIG.ELASTICITY_EXPANSION_LIMIT) continue;
            }

            // --- CONSTRAINT: Rule 1C (Late Stage Tightening) ---
            if (currentDepth >= 3) {
                // If we are deep, restrict max delay to 50% length
                if (atom.delayBeats > (subjectDurationBeats * 0.5)) continue;
            }

            // Calculate next absolute parameters
            const currentDelayDelta = atom.delayBeats;
            const nextStartBeat = prevEntry.startBeat + currentDelayDelta;
            const nextTransposition = prevEntry.transposition + atom.transpositionDiff; 

            // --- CONSTRAINT: Range ---
            if (Math.abs(nextTransposition) > SEARCH_CONFIG.MAX_TOTAL_RANGE) continue;

            // --- CONSTRAINT: Usage Limits ---
            const isInv = atom.type === 'I';
            const absSemi = Math.abs(atom.transpositionDiff % 12);
            const is3rd = [3,4,8,9].includes(absSemi);

            const newStats = { ...state.usageStats };
            if (isInv) newStats.inv++;
            if (is3rd) newStats.third++;

            if (options.inversionMode === 'Max 1' && newStats.inv > 1) continue;
            if (options.thirdSixthMode === 'Max 1' && newStats.third > 1) continue;

            // --- CONSTRAINT: Voice Allocation (Re-entry) ---
            const nextStart16 = Math.round(nextStartBeat * 4);
            let assignedVoice = -1;

            // Try to find a voice that is free
            for (let v = 0; v < options.ensembleTotal; v++) {
                // Must be free at `nextStart16`. Re-entry allowed if start >= previous end
                if (nextStart16 >= state.voiceEndTimes16[v]) {
                    assignedVoice = v;
                    break;
                }
            }

            if (assignedVoice === -1) continue; // No voice available

            // --- CONSTRAINT: Stratification (Rule 4) ---
            // Check against other active voices
            let stratFail = false;
            for (const prev of state.chain) {
                const prevEnd = prev.startBeat + (prev.length/4);
                if (prevEnd > nextStartBeat) {
                    // It is concurrent. Check Stratification.
                    const v1 = prev.voiceIndex;
                    const v2 = assignedVoice;
                    const t1 = prev.transposition;
                    const t2 = nextTransposition;

                    // Enforce V_lower has Lower Pitch
                    // If v2 > v1 (v2 is lower voice), then t2 should be <= t1
                    if (v2 > v1 && t2 > t1) { stratFail = true; break; }
                    if (v1 > v2 && t1 > t2) { stratFail = true; break; }

                    // Specific: V1 vs V3 >= 7 semitones (if applicable)
                    // If |v1 - v2| >= 2, check separation
                    if (Math.abs(v1 - v2) >= 2) {
                        if (Math.abs(t1 - t2) < SEARCH_CONFIG.MIN_SEPARATION_V1_V3) { stratFail = true; break; }
                    }
                }
            }
            if (stratFail) continue;

            // --- ALL HARD CHECKS PASSED ---

            const newEntry: StrettoChainOption = {
                startBeat: nextStartBeat,
                transposition: nextTransposition,
                type: atom.type,
                length: effectiveLen16, // Default full length, truncation handled if needed
                voiceIndex: assignedVoice
            };

            const newVoiceState = [...state.voiceEndTimes16];
            newVoiceState[assignedVoice] = nextStart16 + effectiveLen16;

            const nextState: SearchState = {
                chain: [...state.chain, newEntry],
                voiceEndTimes16: newVoiceState,
                usedTranspositions: [...state.usedTranspositions, nextTransposition],
                historyDelays: [...state.historyDelays, currentDelayDelta],
                usageStats: newStats
            };

            await solve(nextState);
        }
    }

    await solve(rootState);

    // Scoring & Ranking Helper
    function processResult(chain: StrettoChainOption[], validation: ValidationResult, list: StrettoChainResult[]) {
        const log: ScoreLog = { base: 0, penalties: [], bonuses: [], total: 0 };
        let score = 0;

        // Basic Length Bonus
        score += chain.length * 100;

        // Polyphony Bonus
        score += validation.polyphonyIntegral * 10;

        // Dissonance Penalty
        if (validation.polyphonicDuration > 0) {
            const ratio = validation.dissonantDuration / validation.polyphonicDuration;
            if (ratio > 0.4) score -= (ratio * 1000);
        }

        log.total = Math.max(0, score);

        list.push({
            id: `chain-${Date.now()}-${Math.random()}`,
            entries: chain,
            warnings: validation.errors,
            score: log.total,
            scoreLog: log,
            detectedChords: validation.detectedChords,
            dissonanceRatio: validation.polyphonicDuration > 0 ? validation.dissonantDuration/validation.polyphonicDuration : 0
        });

        // Keep top buffer
        list.sort((a,b) => b.score - a.score);
        if (list.length > 50) list.pop();
    }

    return {
        results: validResults,
        stats: {
            nodesVisited,
            timeMs: Date.now() - START_TIME,
            stopReason,
            maxDepthReached
        }
    };
}
